async (params, browser) => {
  // Open Indeed salaries page
  await browser.open('https://www.indeed.com/career/salaries')

  // Wait for search input
  await browser.waitForSelector('input[name="q"], input[id="searchInput"], input[aria-label*="search"], form input[type="text"]', 15000)

  // Let page settle
  await browser.wait(1500)

  // Navigate to salary page for job title
  const nav_result = await browser.evaluate(`const jobTitle = '' + params.job_title + ''; const location = '' + params.location + ''; const baseUrl = 'https://www.indeed.com/career/' + encodeURIComponent(jobTitle.toLowerCase().replace(/\s+/g, '-')) + '/salaries'; const params = new URLSearchParams(); if (location && location !== '{{' + 'location}}' && location.trim()) { params.set('l', location); } window.location.href = baseUrl + (params.toString() ? '?' + params.toString() : ''); return { navigated: true }`)

  // Wait for salary page to load
  await browser.wait(3000)

  // Scroll to load more data
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract salary data
  const salary_data = await browser.evaluate(`const titleEl = document.querySelector('h1, .cmp-SalaryHeader-title, [data-testid="salary-title"]'); const avgSalaryEl = document.querySelector('.cmp-SalaryEstimate-salary, [data-testid="salary-estimate"], .css-1bluz6i, .salary-estimate .css-1uyte9r'); const rangeEl = document.querySelector('.cmp-SalaryEstimate-range, [data-testid="salary-range"], .css-1xe1b0e'); const salaryByCompany = []; const companyEls = document.querySelectorAll('.cmp-SalariesByCompany-row, [data-testid="salary-by-company-row"], .css-1ac7rh0 tr, table tbody tr'); companyEls.forEach(function(row, i) { if (i >= 10) return; const name = row.querySelector('a, td:first-child, .css-1r0wrwl'); const salary = row.querySelector('.css-1bluz6i, td:nth-child(2), .cmp-SalariesByCompany-salary'); if (name && salary) salaryByCompany.push({ company: name.textContent.trim(), salary: salary.textContent.trim() }); }); const salaryByLocation = []; const locationEls = document.querySelectorAll('.cmp-SalariesByLocation-row, [data-testid="salary-by-location-row"], .css-tvghk3 tr'); locationEls.forEach(function(row, i) { if (i >= 10) return; const loc = row.querySelector('a, td:first-child'); const salary = row.querySelector('.css-1bluz6i, td:nth-child(2)'); if (loc && salary) salaryByLocation.push({ location: loc.textContent.trim(), salary: salary.textContent.trim() }); }); const relatedJobs = []; const relatedEls = document.querySelectorAll('.cmp-RelatedJobs-item a, [data-testid="related-job"] a'); relatedEls.forEach(function(el, i) { if (i >= 5) return; relatedJobs.push(el.textContent.trim()); }); return { job_title: titleEl ? titleEl.textContent.trim() : '' + params.job_title + '', average_salary: avgSalaryEl ? avgSalaryEl.textContent.trim() : 'Not available', salary_range: rangeEl ? rangeEl.textContent.trim() : '', salary_by_company: salaryByCompany, salary_by_location: salaryByLocation, related_jobs: relatedJobs, url: window.location.href }`)

  return salary_data
}
